/** Pad a Uint8Array to the next power of 2 (simple reference impl) */
function padToNextPow2(data: Uint8Array): Uint8Array {
  let size = 1;
  while (size < data.length) size *= 2;
  if (size > 65536) throw new RangeError('message_too_long');
  const padded = new Uint8Array(size);
  padded.set(data);
  return padded;
