  // =======================================================================
  describe('Invariants', () => {
    it('channel messages never contain from.pubKey in the serialized package', async () => {
      const padded = await packageMessage('channel msg', 'private', 'ch1');
      const msg = JSON.parse(decode(unpad(padded)));

      expect(msg.from).toBeDefined();
      expect(msg.from.pubKey).toBeUndefined();
      expect('pubKey' in msg.from).toBe(false);
    });

    it('padded frames always have a length that is a power of 2', async () => {
      const sizes = [1, 5, 50, 500, 5000];

      for (const size of sizes) {
        const content = 'a'.repeat(size);
        const padded = await packageMessage(content, 'public');
        expect(isPowerOf2(padded.length)).toBe(true);
        expect(padded.length).toBeLessThanOrEqual(65536);
      }
    });

    it('security-relevant drops use console.warn, not console.error', () => {
      const consoleWarnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});
      const consoleErrorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      // Expired message
      const expiredMsg = {
        id: 'inv_expired_1',
        type: 'public',
        from: { name: 'Bob', pubKey: 'bob_pub' },
        message: 'test',
        signature: fakeSign('test', new Uint8Array(0)),
        timestamp: Date.now() - 120_000,
        ttl: Date.now() - 60_000,
        hops: 0,
      };
      const expiredFrame = padToNextPow2(encode(JSON.stringify(expiredMsg)));
      handleIncomingFrame(
        expiredFrame.buffer.slice(expiredFrame.byteOffset, expiredFrame.byteOffset + expiredFrame.byteLength),
        'ws://s',
      );

      expect(consoleWarnSpy).toHaveBeenCalled();

      // Bad signature message
      const badSigMsg = {
        id: 'inv_badsig_1',
        type: 'public',
        from: { name: 'Bob', pubKey: 'bob_pub' },
        message: 'test',
        signature: 'BADSIG_no_prefix',
        timestamp: Date.now(),
        ttl: Date.now() + 60_000,
        hops: 0,
      };
      const badSigFrame = padToNextPow2(encode(JSON.stringify(badSigMsg)));
      handleIncomingFrame(
        badSigFrame.buffer.slice(badSigFrame.byteOffset, badSigFrame.byteOffset + badSigFrame.byteLength),
        'ws://s',
      );

      // console.warn was called for both
      expect(consoleWarnSpy.mock.calls.length).toBeGreaterThanOrEqual(2);
      // console.error was NOT called for these security drops
      expect(consoleErrorSpy).not.toHaveBeenCalled();
    });

    it('text frames go to discovery handler; binary frames go to message pipeline', () => {
      // Text protocol frame
      const textResult = handleIncomingFrame('PROTO:ping', 'ws://s');
      expect(textResult).toBe('protocol_routed');
      expect(discoveryHandlerCalls).toHaveLength(1);
      expect(messageHandlerCalls).toHaveLength(0);

      // Binary message frame
      const msg = {
        id: 'inv_disc_1',
        type: 'public',
        from: { name: 'Bob', pubKey: 'bob_pub' },
        message: 'binary',
        signature: fakeSign('binary', new Uint8Array(0)),
        timestamp: Date.now(),
        ttl: Date.now() + 60_000,
        hops: 0,
      };
      const padded = padToNextPow2(encode(JSON.stringify(msg)));
      const binResult = handleIncomingFrame(
        padded.buffer.slice(padded.byteOffset, padded.byteOffset + padded.byteLength),
        'ws://s',
      );
      expect(binResult).toBe('delivered');
      expect(messageHandlerCalls).toHaveLength(1);
    });

    it('broadcastMessage accepts both string and Uint8Array without breaking', () => {
      const send = vi.fn();
      peers.set('ws://peer', { send });

      broadcastMessage('text frame');
      broadcastMessage(new Uint8Array([1, 2, 3]));

      expect(send).toHaveBeenCalledTimes(2);
      expect(typeof send.mock.calls[0][0]).toBe('string');
      expect(send.mock.calls[1][0]).toBeInstanceOf(Uint8Array);
    });
  });
});
